import { withDb } from "./db.mjs";

// Enterprise schema: 40 tables with 3NF normalization, FKs, CHECK constraints.
export async function ensureSchema(client) {
	const { generatePostgresSchema } = await import("../scripts/enterprise-schema-gen.mjs");
	const gen = generatePostgresSchema();
	await gen.ensureSchema(client);

	// Add JSONB doc columns and make normalized columns nullable so JSONB-only inserts work
	for (const [table, pk] of [['accounts', 'account_id'], ['orders', 'order_id'], ['invoices', 'invoice_id']]) {
		await client.query(`ALTER TABLE ${table} ADD COLUMN IF NOT EXISTS doc JSONB`);
		const res = await client.query(
			`SELECT column_name FROM information_schema.columns WHERE table_schema = current_schema() AND table_name = $1 AND is_nullable = 'NO' AND column_name != $2`,
			[table, pk]
		);
		for (const row of res.rows) {
			await client.query(`ALTER TABLE "${table}" ALTER COLUMN "${row.column_name}" DROP NOT NULL`);
		}
	}
}

if (import.meta.url === `file://${process.argv[1]}`) {
  withDb((client) => ensureSchema(client)).then(() => console.log("schema ready")).catch((e) => { console.error(e); process.exit(1); });
}
